changeSet.sql:
ALTER TABLE character_stats
    DROP CONSTRAINT IF EXISTS fk_cstat_type;

ALTER TABLE character_wallets
    DROP CONSTRAINT IF EXISTS fk_wallet_currency;

ALTER TABLE wallet_transactions
    DROP CONSTRAINT IF EXISTS fk_wallet_tx_currency;

ALTER TABLE character_known_spells
    DROP CONSTRAINT IF EXISTS fk_cks_spell;

ALTER TABLE characters
    DROP CONSTRAINT IF EXISTS fk_char_background;

rollback.sql:
ALTER TABLE character_stats
    ADD CONSTRAINT fk_cstat_type FOREIGN KEY (stat_type_id) REFERENCES stat_types(id);

ALTER TABLE character_wallets
    ADD CONSTRAINT fk_wallet_currency FOREIGN KEY (currency_type_id) REFERENCES currency_types(id);

ALTER TABLE wallet_transactions
    ADD CONSTRAINT fk_wallet_tx_currency FOREIGN KEY (currency_type_id) REFERENCES currency_types(id);

ALTER TABLE character_known_spells
    ADD CONSTRAINT fk_cks_spell FOREIGN KEY (spell_id) REFERENCES spells(id);

ALTER TABLE characters
    ADD CONSTRAINT fk_char_background FOREIGN KEY (background_id) REFERENCES backgrounds(id);
